The registered functions are defined with the name _ which is the python shorthand for a name that doesn’t matter

Recall we used _ as a placeholder when we wanted to discard a variable in an unpacking

Dispatching occurs through my_print
We could reimplement the pocket calculator using a singledispatch approach


import functools


@functools.singledispatch
def my_evaluate(node):
    raise NotImplementedError


class Integer:
    def __init__(self, value):
        self.value = value


@my_evaluate.register(Integer)
def _(node):
    return node.value


class Add:
    def __init__(self, left, right):
        self.left = left
        self.right = right


@my_evaluate.register(Add)
def _(node):
    return my_evaluate(node.left) + my_evaluate(node.right)


class Multiply:
    def __init__(self, left, right):
        self.left = left
        self.right = right


@my_evaluate.register(Multiply)
def _(node):
    return my_evaluate(node.left) * my_evaluate(node.right)


tree = Multiply(Add(Integer(3), Integer(5)), Add(Integer(4), Integer(7)))
print(my_evaluate(tree))

88



